using System.ComponentModel;
using System.ComponentModel.DataAnnotations;
using HQ.Models.Helpers;
using HQ.Models.Interfaces;

namespace HQ.Plugins.ClaudeCode.Models;

/// <summary>
/// Per-tool argument types. Each is the single source of truth for both the LLM-facing schema
/// (generated by <c>ToolSchemaGenerator</c> from these properties/attributes) and the runtime
/// binding target. Camel-cased property names match the LLM-facing parameter names.
/// </summary>

public class TaskArgs
{
    [Required]
    [Description("The task/instruction for Claude Code (e.g. 'Fix the auth bug in login.ts and add tests')")]
    public string Prompt { get; set; }

    [Description("GitHub repo URL to clone (e.g. 'https://github.com/org/repo'). Optional if repo already cloned in session.")]
    public string RepoUrl { get; set; }

    [Description("Branch to checkout or create for the work")]
    public string Branch { get; set; }

    [Description("Base branch for new branch creation (default: main)")]
    public string BaseBranch { get; set; }

    [Description("Session ID to reuse an existing container. If omitted, a new session is created.")]
    public string SessionId { get; set; }

    [Description("Override max agentic iterations (default from config)")]
    public int? MaxTurns { get; set; }

    [Description("Override tool allowlist (comma-separated, e.g. 'Bash,Read,Edit,Write')")]
    public string AllowedTools { get; set; }

    [Description("Additional system prompt to append (e.g. coding standards, constraints)")]
    public string SystemPrompt { get; set; }
}

public class ContinueArgs
{
    [Required]
    [Description("Session ID from a previous claude_code_task call")]
    public string SessionId { get; set; }

    [Required]
    [Description("Follow-up instruction (e.g. 'Now write tests for the changes you just made')")]
    public string Prompt { get; set; }

    [Description("Override max agentic iterations")]
    public int? MaxTurns { get; set; }

    [Description("Override tool allowlist")]
    public string AllowedTools { get; set; }
}

public class ReviewArgs
{
    [Required]
    [Description("Session ID of the container with changes to review")]
    public string SessionId { get; set; }

    [Description("Review criteria (e.g. 'Check for security vulnerabilities, edge cases, and code style issues'). If omitted, uses a default review prompt.")]
    public string Prompt { get; set; }
}

public class StatusArgs
{
    [Required]
    [Description("Session ID to check")]
    public string SessionId { get; set; }
}

public class GetDiffArgs
{
    [Required]
    [Description("Session ID of the container with changes")]
    public string SessionId { get; set; }
}

/// <summary>
/// Args for claude_code_create_pr. Implements <see cref="IPluginServiceRequest"/> so the framework
/// envelope (notably <c>ConfirmationId</c>) survives the confirmation replay round-trip — the tool
/// uses an inline confirmation flow.
/// </summary>
public class CreatePrArgs : IPluginServiceRequest
{
    [Injected] public string Method { get; set; }
    [Injected] public string ToolCallId { get; set; }
    [Injected] public string RequestingService { get; set; }
    [Injected] public string ConfirmationId { get; set; }

    [Required]
    [Description("Session ID of the container with changes to commit and push")]
    public string SessionId { get; set; }

    [Required]
    [Description("PR creation instructions (e.g. 'Commit all changes and create a PR titled Fix #42: auth bug')")]
    public string Prompt { get; set; }
}

public class DestroySessionArgs
{
    [Required]
    [Description("Session ID to destroy")]
    public string SessionId { get; set; }
}
